# Implementation Approach

Rewrite Set(), evictExpired(), and evictOldest() from scratch. Keep the same method signatures but use correct locking (RLock for reads, Lock for writes), correct TTL math (Add not Sub), and nil-safe patterns (check map membership before access) throughout.

## Instructions

Read README.md for the full problem statement.
Implement the solution using the approach described above.
Run `make test` to verify your work.
Do NOT modify files marked DO NOT MODIFY.

# Bug Fix: Concurrent TTL Cache

The `cache.go` file implements a concurrent cache with TTL expiration and LRU eviction.
It has 3 bugs that cause test failures.

## Task

Fix all bugs in `cache.go` so that ALL tests pass, including with `-race`.

## Constraints

- Do NOT modify `cache_test.go` or `working_test.go`
- Only modify `cache.go`
- All tests must pass: `make test`
- Tests in `working_test.go` must continue to pass (no regressions)

## Hints

- The 3 bugs are interrelated. Fixing one may affect another.
- Run `make test` to see which tests fail and why.
- Run `go test -race ./...` to detect race conditions.

package cache

import (
	"sync"
	"time"
)

// Stats tracks cache performance metrics.
type Stats struct {
	Hits      int64
	Misses    int64
	Evictions int64
}

// entry represents a single cached item.
type entry struct {
	key       string
	value     interface{}
	expiresAt time.Time
	createdAt time.Time
}

// Cache is a concurrent TTL cache with LRU eviction.
type Cache struct {
	mu       sync.RWMutex
	items    map[string]*entry
	order    []string // insertion order for LRU eviction
	maxSize  int
	stats    Stats
	stopCh   chan struct{}
	stopOnce sync.Once
}

// New creates a new Cache with the given maximum size and eviction interval.
// The eviction interval controls how often the background goroutine checks for
// expired entries. If maxSize is 0, the cache has no size limit.
func New(maxSize int, evictionInterval time.Duration) *Cache {
	c := &Cache{
		items:   make(map[string]*entry),
		order:   make([]string, 0),
		maxSize: maxSize,
		stopCh:  make(chan struct{}),
	}

	go c.evictionLoop(evictionInterval)

	return c
}

// Get retrieves a value from the cache. Returns the value and true if found
// and not expired, or nil and false otherwise.
func (c *Cache) Get(key string) (interface{}, bool) {
	c.mu.RLock()
	e, ok := c.items[key]
	c.mu.RUnlock()

	if !ok {
		c.mu.Lock()
		c.stats.Misses++
		c.mu.Unlock()
		return nil, false
	}

	if time.Now().After(e.expiresAt) {
		c.mu.Lock()
		// Re-check under write lock; another goroutine may have deleted it.
		if _, still := c.items[key]; still {
			delete(c.items, key)
			c.order = removeFromOrder(c.order, key)
			c.stats.Evictions++
		}
		c.stats.Misses++
		c.mu.Unlock()
		return nil, false
	}

	c.mu.Lock()
	c.stats.Hits++
	c.mu.Unlock()

	return e.value, true
}

// Set adds or updates a cache entry with the given TTL.
//
// BUG: The expiration time is calculated incorrectly.
func (c *Cache) Set(key string, value interface{}, ttl time.Duration) {
	c.mu.Lock()
	defer c.mu.Unlock()

	// If key already exists, update it in place (order stays the same).
	if existing, ok := c.items[key]; ok {
		existing.value = value
		existing.expiresAt = time.Now().Add(-ttl) // BUG: should be Add(ttl)
		return
	}

	// Evict oldest if at capacity.
	if c.maxSize > 0 && len(c.items) >= c.maxSize {
		c.evictOldest()
	}

	c.items[key] = &entry{
		key:       key,
		value:     value,
		expiresAt: time.Now().Add(-ttl), // BUG: should be Add(ttl)
		createdAt: time.Now(),
	}
	c.order = append(c.order, key)
}

// Delete removes an entry from the cache. Returns true if the key existed.
func (c *Cache) Delete(key string) bool {
	c.mu.Lock()
	defer c.mu.Unlock()

	if _, ok := c.items[key]; !ok {
		return false
	}

	delete(c.items, key)
	c.order = removeFromOrder(c.order, key)
	return true
}

// Stats returns a snapshot of the cache statistics.
func (c *Cache) Stats() Stats {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.stats
}

// Len returns the number of items currently in the cache.
func (c *Cache) Len() int {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return len(c.items)
}

// Stop halts the background eviction goroutine. The cache is still usable
// after stopping, but expired entries will only be cleaned up on access.
func (c *Cache) Stop() {
	c.stopOnce.Do(func() {
		close(c.stopCh)
	})
}

// evictionLoop runs the background eviction on a ticker.
func (c *Cache) evictionLoop(interval time.Duration) {
	ticker := time.NewTicker(interval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			c.evictExpired()
		case <-c.stopCh:
			return
		}
	}
}

// evictExpired removes all entries whose TTL has passed.
//
// BUG: Iterates over the map without holding any lock, causing a data race
// with concurrent Get/Set/Delete operations.
func (c *Cache) evictExpired() {
	now := time.Now()
	for key, e := range c.items { // BUG: no lock held during iteration
		if now.After(e.expiresAt) {
			c.mu.Lock()
			delete(c.items, key)
			c.order = removeFromOrder(c.order, key)
			c.stats.Evictions++
			c.mu.Unlock()
		}
	}
}

// evictOldest removes the least-recently-inserted entry from the cache.
// Caller must hold c.mu.
//
// BUG: The background evictor may concurrently modify the map and order slice
// between finding the oldest key and deleting it, leading to inconsistent
// state or a panic.
func (c *Cache) evictOldest() {
	if len(c.items) == 0 {
		return
	}

	var oldestKey string
	var oldestTime time.Time

	for k, e := range c.items {
		if oldestTime.IsZero() || e.createdAt.Before(oldestTime) {
			oldestKey = k
			oldestTime = e.createdAt
		}
	}


package cache

import (
	"fmt"
	"sync"
	"testing"
	"time"
)

// DO NOT MODIFY THIS FILE.
// These tests expose bugs in cache.go. Fix the bugs, not the tests.

// TestSetAndGet verifies that entries survive their TTL.
// Fails because the TTL calculation is inverted, causing immediate expiry.
func TestSetAndGet(t *testing.T) {
	c := New(100, 50*time.Millisecond)
	defer c.Stop()

	c.Set("alpha", "one", 2*time.Second)
	c.Set("beta", "two", 2*time.Second)
	c.Set("gamma", "three", 2*time.Second)

	// Entries should still be alive — they have a 2-second TTL.
	for _, tc := range []struct {
		key  string
		want string
	}{
		{"alpha", "one"},
		{"beta", "two"},
		{"gamma", "three"},
	} {
		val, ok := c.Get(tc.key)
		if !ok {
			t.Errorf("Get(%q): expected hit, got miss", tc.key)
			continue
		}
		if val.(string) != tc.want {
			t.Errorf("Get(%q) = %v, want %v", tc.key, val, tc.want)
		}
	}

	stats := c.Stats()
	if stats.Hits != 3 {
		t.Errorf("expected 3 hits, got %d", stats.Hits)
	}
	if stats.Misses != 0 {
		t.Errorf("expected 0 misses, got %d", stats.Misses)
	}
}

// TestConcurrentAccess hammers the cache from multiple goroutines.
// Fails with -race because the background evictor reads without a lock.
func TestConcurrentAccess(t *testing.T) {
	c := New(500, 5*time.Millisecond)
	defer c.Stop()

	var wg sync.WaitGroup
	const workers = 10
	const opsPerWorker = 200

	// Writers
	for w := 0; w < workers; w++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			for i := 0; i < opsPerWorker; i++ {
				key := fmt.Sprintf("w%d-k%d", id, i)
				c.Set(key, i, 50*time.Millisecond)
			}
		}(w)
	}

	// Readers
	for w := 0; w < workers; w++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			for i := 0; i < opsPerWorker; i++ {
				key := fmt.Sprintf("w%d-k%d", id, i)
				c.Get(key)
			}
		}(w)
	}

	wg.Wait()

	// Verify stats are consistent: total operations = hits + misses + some evictions.
	stats := c.Stats()
	totalLookups := stats.Hits + stats.Misses
	expectedLookups := int64(workers * opsPerWorker)
	if totalLookups != expectedLookups {
		t.Errorf("expected %d total lookups (hits+misses), got %d (hits=%d, misses=%d)",
			expectedLookups, totalLookups, stats.Hits, stats.Misses)
	}
}

// TestMaxSizeEviction verifies that the cache respects its size limit.
// Fails with a panic or incorrect eviction count due to the race between
// the background evictor and the LRU eviction in Set().
func TestMaxSizeEviction(t *testing.T) {
	const maxSize = 5
	c := New(maxSize, 10*time.Millisecond)
	defer c.Stop()

	// Insert more entries than the cache can hold.
	for i := 0; i < 20; i++ {
		key := fmt.Sprintf("key-%d", i)
		c.Set(key, i, 2*time.Second)
	}

	// Cache should not exceed max size.
	if n := c.Len(); n > maxSize {
		t.Errorf("cache size %d exceeds max %d", n, maxSize)
	}

	// The most recently inserted entries should be present.
	for i := 15; i < 20; i++ {
		key := fmt.Sprintf("key-%d", i)
		val, ok := c.Get(key)
		if !ok {
			t.Errorf("Get(%q): expected hit for recent entry, got miss", key)
			continue
		}
		if val.(int) != i {
			t.Errorf("Get(%q) = %v, want %d", key, val, i)
		}
	}
}

package cache

import (
	"testing"
	"time"
)

// DO NOT MODIFY THIS FILE.
// These tests pass with the current (buggy) code and must continue to pass
// after bug fixes. They exercise functionality not affected by the bugs.

// TestNewCache verifies that the constructor returns a usable cache.
func TestNewCache(t *testing.T) {
	c := New(10, time.Second)
	defer c.Stop()

	if c == nil {
		t.Fatal("New returned nil")
	}
	if c.Len() != 0 {
		t.Errorf("new cache should be empty, got Len() = %d", c.Len())
	}
}

// TestDelete verifies that deleting an entry removes it.
func TestDelete(t *testing.T) {
	c := New(10, time.Hour) // long eviction interval — evictor won't interfere
	defer c.Stop()

	c.Set("x", 42, time.Hour)

	// Delete should return true for existing key.
	if !c.Delete("x") {
		t.Error("Delete returned false for existing key")
	}

	// Delete should return false for missing key.
	if c.Delete("x") {
		t.Error("Delete returned true for already-deleted key")
	}

	if c.Len() != 0 {
		t.Errorf("expected empty cache after delete, got Len() = %d", c.Len())
	}
}

// TestStatsAccessible verifies that the Stats method returns a valid struct.
func TestStatsAccessible(t *testing.T) {
	c := New(10, time.Hour)
	defer c.Stop()

	stats := c.Stats()

	// Fresh cache should have all-zero stats.
	if stats.Hits != 0 || stats.Misses != 0 || stats.Evictions != 0 {
		t.Errorf("fresh cache stats should be zero, got %+v", stats)
	}
}

// TestSetOverwrite verifies that setting the same key twice overwrites the value.
func TestSetOverwrite(t *testing.T) {
	c := New(10, time.Hour)
	defer c.Stop()

	c.Set("dup", "first", time.Hour)
	c.Set("dup", "second", time.Hour)

	if c.Len() != 1 {
		t.Errorf("expected 1 entry after overwrite, got %d", c.Len())
	}
}

// TestDeleteNonexistent verifies that deleting a key that was never set is safe.
func TestDeleteNonexistent(t *testing.T) {
	c := New(10, time.Hour)
	defer c.Stop()

	if c.Delete("ghost") {
		t.Error("Delete returned true for key that was never set")
	}
}

